#!/bin/bash
BUCKET="gs://genius-makers-academy/past-papers/past-papers/NSC"
TMPDIR="/tmp/gma_papers"
mkdir -p $TMPDIR
SUCCESS=0
FAILED=0

dl() {
  local URL="$1"
  local PATH="$2"
  local FILE="$3"
  curl -L --silent --fail --max-time 30 -o "$TMPDIR/$FILE" "$URL" 2>/dev/null
  if [ -f "$TMPDIR/$FILE" ] && [ -s "$TMPDIR/$FILE" ]; then
    local SIZE=$(wc -c < "$TMPDIR/$FILE")
    if [ "$SIZE" -gt 10000 ]; then
      gsutil -q cp "$TMPDIR/$FILE" "$BUCKET/$PATH/$FILE"
      echo "✅ $FILE"
      SUCCESS=$((SUCCESS + 1))
    else
      echo "⚠️  Too small: $FILE"
      FAILED=$((FAILED + 1))
    fi
    rm -f "$TMPDIR/$FILE"
  else
    echo "❌ Not found: $FILE"
    FAILED=$((FAILED + 1))
  fi
}

